# Example: OSS license check in a pre-commit hook or CI script
# Requires: pip install pip-licenses (Python) or syft (SBOM)
import subprocess, json, sys

PROHIBITED_LICENSES = {
    "GPL-2.0", "GPL-2.0-only", "GPL-2.0-or-later",
    "GPL-3.0", "GPL-3.0-only", "GPL-3.0-or-later",
    "AGPL-3.0", "AGPL-3.0-only", "AGPL-3.0-or-later",
    "SSPL-1.0",
}
REVIEW_REQUIRED_LICENSES = {
    "LGPL-2.0", "LGPL-2.1", "LGPL-3.0", "MPL-2.0", "EPL-2.0", "CDDL-1.0",
}

def check_python_dependencies() -> tuple[list[str], list[str]]:
    result = subprocess.run(
        ["pip-licenses", "--format=json", "--with-license-file"],
        capture_output=True, text=True
    )
    packages = json.loads(result.stdout)
    blocked = []
    flagged = []
    for pkg in packages:
        lic = pkg.get("License", "Unknown").strip()
        # Normalize to SPDX-like
        if any(p in lic for p in ("GPL-3", "GPL 3", "GNU General Public License v3")):
            lic_spdx = "GPL-3.0-only"
        elif "AGPL" in lic:
            lic_spdx = "AGPL-3.0-only"
        else:
            lic_spdx = lic
        if lic_spdx in PROHIBITED_LICENSES:
            blocked.append(f"{pkg['Name']} ({lic})")
        elif lic_spdx in REVIEW_REQUIRED_LICENSES:
            flagged.append(f"{pkg['Name']} ({lic}) — Legal review required")
    return blocked, flagged

blocked, flagged = check_python_dependencies()
if blocked:
    print("ERROR: Prohibited licenses found:")
    for b in blocked:
        print(f"  BLOCKED: {b}")
    sys.exit(1)
if flagged:
    print("WARNING: Review-required licenses found:")
    for f in flagged:
        print(f"  REVIEW: {f}")
    print("Obtain Legal sign-off before merging.")
    # Do not block CI — flagged items require human review
print("License check complete.")
